const webhookBody = $('Webhook - Release Published').item.json.body;
const release = webhookBody.release;
const repo = webhookBody.repository;

const releases = $('GitHub - Get Last 2 Releases').item.json;
const commits = $('GitHub - Get Recent Commits').item.json;

// ── Build changelog from commit messages ──────────────────────────
const commitList = Array.isArray(commits) ? commits : [];

const CONV_COMMIT = [
  { prefix: /^feat(\(.*?\))?:/i,     section: '✨ Features',     items: [] },
  { prefix: /^fix(\(.*?\))?:/i,      section: '🐛 Bug Fixes',    items: [] },
  { prefix: /^perf(\(.*?\))?:/i,     section: '⚡ Performance',   items: [] },
  { prefix: /^docs(\(.*?\))?:/i,     section: '📚 Documentation', items: [] },
  { prefix: /^refactor(\(.*?\))?:/i, section: '♻️ Refactoring',   items: [] },
  { prefix: /^chore(\(.*?\))?:/i,    section: '🔧 Maintenance',   items: [] },
];
const OTHER = { section: '📝 Other Changes', items: [] };

for (const commit of commitList.slice(0, 30)) {
  const msg = (commit.commit?.message || '').split('\n')[0].trim();
  const sha = (commit.sha || '').substring(0, 7);
  const author = commit.commit?.author?.name || 'unknown';
  const url = commit.html_url || '';
  const entry = `- ${msg} ([\`${sha}\`](${url})) — *${author}*`;

  let matched = false;
  for (const cat of CONV_COMMIT) {
    if (cat.prefix.test(msg)) { cat.items.push(entry); matched = true; break; }
  }
  if (!matched) OTHER.items.push(entry);
}

const allSections = [...CONV_COMMIT, OTHER].filter(s => s.items.length > 0);
const changelogMd = allSections.map(s => `### ${s.section}\n${s.items.join('\n')}`).join('\n\n');

// ── Release metadata ──────────────────────────────────────────────
const prevRelease = Array.isArray(releases) && releases.length > 1 ? releases[1] : null;
const isPrerelease = release.prerelease;
const tag = release.tag_name;
const releaseName = release.name || tag;
const publishedAt = new Date(release.published_at).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const author = release.author?.login || 'unknown';
const totalCommits = commitList.length;

// ── Stats ─────────────────────────────────────────────────────────
const featCount   = CONV_COMMIT.find(c => c.section.includes('Feature'))?.items.length || 0;
const fixCount    = CONV_COMMIT.find(c => c.section.includes('Bug'))?.items.length || 0;
const contributors = [...new Set(commitList.map(c => c.commit?.author?.name).filter(Boolean))];

// ── Formatted changelog for GitHub release body update ───────────
const fullChangelog = `## What's Changed\n\n${changelogMd}\n\n**Full Changelog**: ${prevRelease ? `[${prevRelease.tag_name}...${tag}](${repo.html_url}/compare/${prevRelease.tag_name}...${tag})` : repo.html_url + '/commits/' + tag}`;

// ── HTML email body ───────────────────────────────────────────────
const htmlEmail = `<div style="font-family:Arial,sans-serif;max-width:640px;margin:0 auto">
  <div style="background:#24292e;padding:24px;border-radius:8px 8px 0 0;text-align:center">
    <h1 style="color:white;margin:0">${isPrerelease ? '🧪 Pre-release' : '🚀 Release'}: ${releaseName}</h1>
    <p style="color:#8b949e;margin:8px 0 0">${repo.full_name} · ${publishedAt}</p>
  </div>
  <div style="background:#f6f8fa;padding:24px;border:1px solid #e1e4e8;border-radius:0 0 8px 8px">
    <div style="display:flex;gap:16px;margin-bottom:24px;flex-wrap:wrap">
      <div style="background:white;border:1px solid #e1e4e8;border-radius:8px;padding:16px;flex:1;text-align:center;min-width:100px">
        <div style="font-size:28px;font-weight:bold;color:#0366d6">${totalCommits}</div>
        <div style="color:#586069;font-size:12px">Commits</div>
      </div>
      <div style="background:white;border:1px solid #e1e4e8;border-radius:8px;padding:16px;flex:1;text-align:center;min-width:100px">
        <div style="font-size:28px;font-weight:bold;color:#28a745">${featCount}</div>
        <div style="color:#586069;font-size:12px">Features</div>
      </div>
      <div style="background:white;border:1px solid #e1e4e8;border-radius:8px;padding:16px;flex:1;text-align:center;min-width:100px">
        <div style="font-size:28px;font-weight:bold;color:#e36209">${fixCount}</div>
        <div style="color:#586069;font-size:12px">Bug Fixes</div>
      </div>
      <div style="background:white;border:1px solid #e1e4e8;border-radius:8px;padding:16px;flex:1;text-align:center;min-width:100px">
        <div style="font-size:28px;font-weight:bold;color:#6f42c1">${contributors.length}</div>
        <div style="color:#586069;font-size:12px">Contributors</div>
      </div>
    </div>
    <h2>Changelog</h2>
    <pre style="background:white;border:1px solid #e1e4e8;border-radius:6px;padding:16px;font-size:13px;white-space:pre-wrap;overflow-x:auto">${fullChangelog.replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre>
    ${contributors.length > 0 ? `<h3>Contributors</h3><p>${contributors.map(c => `<strong>${c}</strong>`).join(', ')}</p>` : ''}
    <div style="margin-top:24px;text-align:center">
      <a href="${release.html_url}" style="background:#0366d6;color:white;padding:12px 28px;text-decoration:none;border-radius:6px;display:inline-block">View Release on GitHub →</a>
    </div>
  </div>
</div>`;

return [{
  json: {
    tag, releaseName, publishedAt, author, isPrerelease,
    repo_name: repo.full_name,
    repo_url: repo.html_url,
    release_url: release.html_url,
    total_commits: totalCommits,
    feat_count: featCount,
    fix_count: fixCount,
    contributors: contributors.join(', ') || 'N/A',
    contributor_count: contributors.length,
    changelog_md: fullChangelog,
    full_changelog_text: changelogMd,
    html_email: htmlEmail,
    email_subject: `${isPrerelease ? '🧪' : '🚀'} ${repo.name} ${tag} ${isPrerelease ? 'Pre-release' : 'Released'}`,
    discord_message: `${isPrerelease ? '🧪' : '🚀'} **${releaseName}** is live!\n\`${tag}\` · ${repo.full_name}\n📊 ${totalCommits} commits · ✨ ${featCount} features · 🐛 ${fixCount} fixes · 👥 ${contributors.length} contributors\n🔗 ${release.html_url}`,
    telegram_message: `${isPrerelease ? '🧪' : '🚀'} *${releaseName} Released*\n\n\`${tag}\` — ${repo.full_name}\n\n📊 ${totalCommits} commits\n✨ ${featCount} new features\n🐛 ${fixCount} bug fixes\n👥 ${contributors.length} contributor${contributors.length !== 1 ? 's' : ''}\n\n[View on GitHub](${release.html_url})`
  }
}];
